(window.courseContentFiles = window.courseContentFiles || {})["000002/0002"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote>Горе долу довършена</blockquote><h1 style=\"text-align: center\">ИНТЕРПРЕТАЦИЯ НА ЕЛЕКТРОКАРДИОГРАМАТА</h1><p>От техническа гледна точка ЕКГ се записва върху милиметрова хартия, разделена на линии през <strong>1 mm</strong> в хоризонтална и вертикална посока. Всяка пета линия е удебелена за улесняване на измерването.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Технически стандарти</h2><ul><li><strong>Вертикална ос (Волтаж):</strong> Измерва се в миливолти (mV). В стандартния случай <strong>1 mm = 0,1 mV</strong>.</li><li><strong>Хоризонтална ос (Време):</strong> Стандартната скорост на запис е <strong>25 mm/sec</strong>.</li><ul><li><strong>1 mm</strong> (малко квадратче) = <strong>0,04 sec</strong>.</li><li><strong>5 mm</strong> (дебела линия / голямо квадратче) = <strong>0,2 sec</strong>.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Последователност на анализа</h2><p>За да се избегне пропускането на дискретни аномалии, се следва стандартен ред:</p><ol><li><strong>Проверка на калибрацията</strong> на волтажа.</li><li><strong>Сърдечен ритъм</strong>.</li><li><strong>Сърдечна честота</strong>.</li><li><strong>Интервали</strong> (PR, QRS, QT).</li><li><strong>Средна QRS ос</strong>.</li><li><strong>Аномалии на P-вълната</strong>.</li><li><strong>Аномалии на QRS</strong> (хипертрофия, бедрен блок, инфаркт).</li><li><strong>Аномалии на ST-сегмента и T-вълната</strong>.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>1. Калибрация</h2><p>ЕКГ апаратите рутинно изписват вертикален сигнал от <strong>1,0 mV</strong> в началото или края на записа.</p><ul><li><strong>Нормален волтаж:</strong> Калибрационният маркер е с височина <strong>10 mm</strong> (1 mm = 0,1 mV).</li><li><strong>Половин волтаж:</strong> Използва се при висок волтаж на QRS (напр. левокамерна хипертрофия или блокове), когато зъбците не се събират на хартията. Маркерът е висок <strong>5 mm</strong> (1 mm = <strong>0,2 mV</strong>).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>2. Сърдечен ритъм</h2><p>Нормалният синусов ритъм е налице, ако:</p><ol><li>Всяка <strong>P-вълна</strong> е последвана от QRS.</li><li>Всеки <strong>QRS</strong> е предшестван от P-вълна.</li><li>P-вълната е <strong>положителна</strong> в отвеждания <strong>I, II и III</strong>.</li><li><strong>PR-интервалът</strong> е по-голям от <strong>0,12 sec</strong> (3 малки квадратчета).</li></ol><ul><li><strong>Синусова брадикардия:</strong> &lt; 60 bpm.</li><li><strong>Синусова тахикардия:</strong> &gt; 100 bpm.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>3. Сърдечна честота</h2><ul><li><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774014859804-image.png &quot;width=100%&quot;)\" id=\"note-1774014866526-0\">Стандартен метод:</span></strong> Стандартната формула при скорост 25 mm/sec е: <strong>1500/броя на малките квадратчета между 2 R зъбеца.</strong></p><br></li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774014883162-image.png &quot;width=100%&quot;) **300-150-100-75-60-50 се помни лесно, защото всяко число е частно на 300.**\" id=\"note-1774014966078-1\">Метод на големите квадратчета:</span></strong> Броене на дебелите линии между два R-зъбеца по последователността: <strong>300 — 150 — 100 — 75 — 60 — 50</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>4. <span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774015061659-image.png &quot;width=100%&quot;)\" id=\"note-1774015063186-2\">Интервали (PR, QRS, QT)</span></h2><p>Измерват се в отвеждането, където интервалът е с най-голяма продължителност.</p><ul><li><strong>PR интервал:</strong> От началото на P-вълната до началото на QRS.</li><li><strong>QRS интервал:</strong> От началото до края на QRS комплекса.</li><li><strong>QT интервал:</strong> От началото на QRS до края на T-вълната.</li><li><strong>Коригиран QT (QTc):</strong> Тъй като QT варира според честотата, се изчислява като се раздели измерения QT на корен квадратен от RR-интервала.</li><li><strong>Визуално правило:</strong> При нормална честота (60-100 bpm), ако <strong>QT &lt; 1/2 от RR-интервала</strong>, той е в норма.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>5. Средна QRS ос</h2><p>Представлява средната стойност на моментните електрически сили по време на камерната деполяризация във фронталната равнина.</p><ul><li><strong>Нормална стойност:</strong> Между <strong>-30° и +90°</strong>.</li><li><strong>Ляво отклонение (Left axis deviation):</strong> По-отрицателна от <strong>-30°</strong>.</li><li><strong>Дясно отклонение (Right axis deviation):</strong> По-голяма от <strong>+90°</strong>.</li></ul><h3>Определяне на средната QRS ос:</h3><ul><li><strong>Огледайте периферните отвеждания I и II.</strong> Ако QRS комплексът е предимно положителен и в двете, тогава оста е <strong>нормална </strong>и сте готови. Ако не е, преминете към следващата стъпка.</li><li><strong>Огледайте шестте периферни отвеждания</strong> и определете в кое от тях QRS комплексът е най-близо до <strong>изоелектричната линия</strong>. Средната ос е перпендикулярна на това отвеждане.</li><li><strong>Огледайте отвеждането, което е перпендикулярно на отвеждането с изоелектричния комплекс</strong>. Ако QRS в това перпендикулярно отвеждане е предимно положителен, тогава средната ос сочи към <strong>положителния </strong>(+) полюс на това отвеждане. Ако е предимно отрицателен, тогава средната QRS ос сочи към <strong>отрицателния </strong>(-) полюс на това отвеждане.</li></ul><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773951832375-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773951832375-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773951832375-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 572px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>6. Аномалии на P-вълната</h2><p>P-вълната представлява деполяризацията на дясното предсърдие, последвана бързо от деполяризацията на лявото предсърдие; двата компонента са почти насложени един върху друг. P-вълната обикновено се визуализира най-добре в <strong>отвеждане II</strong> – отвеждането, което е най-паралелно на потока на електрическия ток през предсърдията от синусовия до AV-възела.</p><h4>Увеличение на дясното предсърдие</h4><p>Когато дясното предсърдие е увеличено, началният компонент на P-вълната е по-голям от нормалното.</p><ul><li><strong>Критерий:</strong> P-вълната е по-висока от <strong>2,5 mm</strong> в отвеждане II.</li></ul><h4>Увеличение на лявото предсърдие</h4><p>Увеличението на лявото предсърдие се наблюдава най-добре в <strong>отвеждане V1</strong>. Обикновено в V1 се записва P-вълна с първоначално положително отклонение, отразяващо деполяризацията на дясното предсърдие насочена антериорно, последвано от отрицателно отклонение, дължащо се на силите на лявото предсърдие, ориентирани постериорно.</p><ul><li><strong>Критерий:</strong> Увеличението на лявото предсърдие се манифестира с по-голямо от нормалното отрицателно отклонение в V1 – най-малко <strong>1 mm широко и 1 mm дълбоко</strong>.</li></ul><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774015423620-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774015423620-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774015423620-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 438px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Камерна хипертрофия</h1><p>Хипертрофията на лявата или дясната камера кара засегнатата кухина да генерира по-голяма от нормалната електрическа активност. Обикновено лявата камера, която е с по-дебели стени, произвежда по-доминиращи сили от тези на дясната.</p><h2>Дяснокамерна хипертрофия</h2><p>При това състояние десностранните електрически сили се засилват и започват да доминират над тези на лявата камера.</p><ul><li>Във<strong> </strong><strong>V1 и V2</strong> отвежданията&nbsp;<strong>R-зъбецът става по-висок от S-зъбеца</strong>.</li><li>Във <strong>V5 и V6 </strong>отвежданията&nbsp;<strong>S-зъбецът става по-висок от R-зъбеца</strong>.</li><li>Наблюдава се отклонение на <strong>съдечната ос надясно</strong> (над +90°).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Левокамерна хипертрофия</h2><p>При нея се генерират по-големи от нормалното сили от лявата камера, което засилва нормалната ЕКГ картина.</p><ul><li>Във&nbsp;<strong>V5 и V6 </strong>отвежданията се показват много високи R-зъбци, като амплитудата на R във V5 или V6 надвишава 26 mm.</li><li>Във<strong> </strong><strong>V1 и V2</strong> отвежданията се демонстрират много дълбоки S-зъбци, като амплитудата на S във V1 често надвишава 24 mm.</li><li><strong>Критерии за левокамерна хипертрофия:</strong></li><ul><li>Сборът от амплитудите на S в V1 и R във V5 (или V6) е по-голям от 35 мм.</li><li>R в aVL + S във V3 &gt; 28 мм за мъже и &gt; 20 мм за жени.</li><li>R вълната в aVL ≥ 11 мм.</li></ul></ul><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773952139925-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773952139925-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773952139925-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1105px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Бедрени блокове</h1><p>Прекъсването на проводимостта през десния или левия бедрен клон може да се развие вследствие на исхемично или дегенеративно увреждане. В резултат на това засегнатата камера не се деполяризира в нормалната си последователност. Вместо бърза и равномерна стимулация чрез влакната на Пуркиние, клетките на тази камера трябва да разчитат на относително бавно разпространение на електрическата активност от миоцит към миоцит, идващо от незасегнатата камера. Този забавен процес удължава деполяризацията и разширява QRS комплекса.</p><ul><li><strong>Нормална продължителност на QRS:</strong> 0,10 sec.</li><li><strong>Непълен бедрен блок:</strong> Продължителност на QRS между <strong>0,10–0,12 sec</strong>.</li><li><strong>Пълен бедрен блок:</strong> Продължителност на QRS над <strong>0,12 sec</strong>.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773952520245-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773952520245-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/notes-images/2026/03/1773952520245-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1208px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Десен бедрен блок (RBBB)</h2><p>При десния бедрен блок (RBBB) провеждането на импулса през десния клон на снопа на Хис е прекъснато. Това води до специфични промени в ЕКГ.</p><h3>Диагностични критерии</h3><p>За да се постави диагноза RBBB, трябва да са налице следните белези:</p><ul><li><strong>Широк QRS комплекс:</strong> Продължителност над 0,12 sec.</li><li><strong>rSR’ модел в V1-V3:</strong> Първоначално малко положително отклонение (R), последвано от по-голямо отрицателно (S) и втори висок R-зъбец (R’).</li><li><strong>Широк, „разлят“ S-зъбец:</strong> Наблюдава се в левите латерални отвеждания (<strong>I, aVL, V5-V6</strong>).</li></ul><h3>Мнемоника: MaRRoW</h3><p>Името <strong>MaRRoW</strong> помага за бързо разпознаване на десния блок (двете <strong>RR</strong> в средата насочват към <strong>R</strong>ight bundle branch block):</p><ul><li><strong>M (първата буква):</strong> Комплексите в <strong>V1</strong> наподобяват буквата <strong>M</strong> (<strong>rSR'</strong> конфигурация приличаща на \"<strong>заешки уши</strong>\").</li><li><strong>W (последната буква):</strong> Комплексите в <strong>V6</strong> наподобяват буквата <strong>W</strong> (първоначален малък Q, висок R и широк, разлят S-зъбец накрая).</li></ul><h3>Патофизиология</h3><p>Процесът на деполяризация при RBBB протича по следния начин:</p><ol><li>Синусовият възел и AV-възелът функционират нормално.</li><li>Деполяризацията преминава през снопа на Хис, но продължава <strong>само по левия бедрен клон</strong>.</li><li>Септумът и стената на лявата камера се деполяризират нормално.</li><li>Стените на дясната камера се деполяризират едва по-късно чрез импулс от левия клон. Това става по <strong>бавен и по-малко ефективен път</strong> (от клетка на клетка).</li></ol><h3>Клинично значение</h3><p>Десният бедрен блок може да бъде както физиологичен вариант, така и резултат от увреждане. Възможните причини включват:</p><ul><li><strong>Белодробна патология:</strong> ХОББ, белодробен емболизъм, cor pulmonale.</li><li><strong>Сърдечни заболявания:</strong> Исхемична болест на сърцето, вродени дефекти (например предсърден септален дефект - ASD), първични заболявания на миокарда или дегенерация на проводната система.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775141722741-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775141722741-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 451px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Ляв бедрен блок (LBBB)</h2><p>При LBBB проводимостта през левия клон на снопа на Хис е прекъсната. За разлика от десния блок, LBBB почти винаги е признак на подлежащо заболяване.</p><h3>Диагностични критерии</h3><p>Основните ЕКГ белези за диагноза на LBBB са:</p><ul><li><strong>Широк QRS комплекс:</strong> Продължителност над <p>0,12 sec.</p></li><li><strong>Доминиращ S-зъбец в V1.</strong></li><li><strong>Широк, монофазен R-зъбец:</strong> Наблюдава се в левите латерални отвеждания (<strong>I, aVL, V5-V6</strong>).</li><li><strong>Липса на Q-зъбци</strong> в левите латерални отвеждания.</li><li><strong>Удължен R-зъбец (&gt;60 ms)</strong> в отвеждания V5-V6.</li></ul><h3>Мнемоника: WiLLiaM</h3><p>Името <strong>WiLLiaM</strong> помага за бързо разпознаване на левия блок (двете <strong>LL</strong> в средата насочват към <strong>L</strong>eft bundle branch block):</p><ul><li><strong>W (първата буква):</strong> Комплексите в <strong>V1</strong> наподобяват буквата <strong>W</strong> – дълбоко отрицателно отклонение (доминиращ S-зъбец), който може да бъде назъбен.</li><li><strong>M (последната буква):</strong> Комплексите в <strong>V6</strong> наподобяват буквата <strong>M</strong> – широк, назъбен или с форма на „M“ R-зъбец.</li></ul><h3>Патофизиология</h3><p>При LBBB нормалният път на импулса е променен по следния начин:</p><ol><li>Деполяризацията преминава през снопа на Хис <strong>само по десния бедрен клон</strong>.</li><li><strong>Септумът се деполяризира анормално</strong> – от дясно на ляво (обратно на нормалното).</li><li>Стената на дясната камера се деполяризира нормално.</li><li>Стените на лявата камера се деполяризират едва накрая чрез импулс от десния клон, преминаващ по <strong>бавен и по-малко ефективен път</strong>.</li></ol><h3>Клинично значение</h3><p>Левият бедрен блок <strong>винаги е патологичен</strong> (не се среща при здрави хора като физиологичен вариант). Възможните причини включват:</p><ul><li><strong>Дегенерация на проводната система.</strong></li><li><strong>Миокардни патологии:</strong> Исхемична болест на сърцето, кардиомиопатия или клапни пороци.</li><li><strong>Следкардиологични процедури:</strong> Увреждане на левия клон или снопа на Хис по време на интервенция.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775141703862-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775141703862-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 441px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: left\">Фасцикуларни блокове</h2><p>Левият бедрен клон се подразделя на две основни деления, наречени фасцикули: <strong>ляв преден фасцикул</strong> и <strong>ляв заден фасцикул</strong>. Въпреки че LBBB предполага, че проводимостта е блокирана в целия ляв бедрен клон, увреждане може да настъпи и само в един от двата фасцикула, което води до ляв преден или ляв заден фасцикуларен блок (наричани още <strong>хемиблокове</strong>). Основното значение на фасцикуларните блокове при интерпретацията на ЕКГ е, че те могат значително да променят средната ЕКГ ос.</p><p>За разлика от RBBB и LBBB, LAFB и LPFB <strong>не водят до значително разширяване на QRS</strong>, тъй като бързо провеждащите влакна на Пуркиние свързват териториите на двата фасцикула. Общото време за деполяризация е само леко удължено. Докато LBBB и RBBB се разпознават най-лесно в прекордиалните отвеждания, при LAFB и LPFB най-полезни са записите в <strong>периферните отвеждания</strong>.</p><p>Анатомично, предният фасцикул на левия клон преминава по предната част на лявата камера към предния папиларен мускул (разположен в предната и горната част на кухината), докато задният фасцикул се движи към задния папиларен мускул (разположен в задната, долната и медиалната част на лявата камера). При нормални условия проводимостта чрез двата фасцикула протича едновременно, така че електрическата активация на лявата камера е равномерна. Ако обаче проводимостта в едно от двете деления е блокирана, първоначалната деполяризация на лявата камера възниква изключително от незасегнатия фасцикул.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774017059169-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774017059169-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 856px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h2>Ляв преден фасцикуларен блок (LAFB)</h2><p>Левият преден фасцикуларен блок (LAFB) възниква, когато предното разклонение на левия бедрен клон е прекъснато. Това води до специфично пренасочване на електрическата активност на сърцето нагоре и наляво.</p><h3>Диагностични критерии</h3><p>Основните ЕКГ характеристики на LAFB включват:</p><ul><li><strong>Отклонение на електрическата ос наляво:</strong> Обикновено между <strong>-45° и -90°</strong>.</li><li><strong>Специфични QRS конфигурации:</strong></li><ul><li><strong>qR комплекси</strong> в отвеждания <strong>I и aVL</strong> (малък Q-зъбец и висок R-зъбец).</li><li><strong>rS комплекси</strong> в отвеждания <strong>II, III и aVF</strong> (малък R-зъбец и дълбок S-зъбец).</li></ul><li><strong>Удължено време до пика на R-зъбеца:</strong> В отвеждане <strong>aVL &gt; 45 ms</strong>.</li></ul><h3>Типични ЕКГ белези</h3><p>При анализ на ЕКГ запис за LAFB се наблюдават следните закономерности:</p><ul><li><strong>В отвеждания II, III и aVF:</strong> Комплексите са доминиращо <strong>ОТРИЦАТЕЛНИ</strong> (дълбоки S-зъбци).</li><li><strong>В отвеждания I и aVL:</strong> Комплексите са доминиращо <strong>ПОЛОЖИТЕЛНИ</strong> (високи R-зъбци).</li><li><strong>Продължителност на QRS:</strong> Обикновено е нормална или съвсем леко удължена (<strong>80-110 ms</strong>), тъй като основният ляв бедрен клон все още функционира</li></ul><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775142688666-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775142688666-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775142688666-image.png\" data-width=\"70\" data-align=\"center\" style=\"width: 1134.7px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><h2>Ляв заден фасцикуларен блок (LPFB)</h2><p>Левият заден фасцикуларен блок (LPFB) възниква при прекъсване на задното разклонение на левия бедрен клон. Тъй като това разклонение е по-дебело и по-добре кръвоснабдено от предното, неговото изолирано блокиране е по-рядко срещано.</p><h3>Диагностични критерии</h3><p>Основните ЕКГ характеристики на LPFB включват:</p><ul><li><strong>Отклонение на електрическата ос надясно:</strong> Обикновено над <strong>+90°</strong>.</li><li><strong>Специфични QRS конфигурации:</strong></li><ul><li><strong>rS комплекси</strong> в отвеждания <strong>I и aVL</strong> (малък R-зъбец и дълбок S-зъбец).</li><li><strong>qR комплекси</strong> в отвеждания <strong>II, III и aVF</strong> (малък Q-зъбец и висок R-зъбец).</li></ul><li><strong>Удължено време до пика на R-зъбеца:</strong> В отвеждане <strong>aVF</strong>.</li></ul><h3>Типични ЕКГ белези</h3><p>При анализ на ЕКГ запис за LPFB се наблюдават следните закономерности:</p><ul><li><strong>В отвеждания II, III и aVF:</strong> Комплексите са доминиращо <strong>ПОЛОЖИТЕЛНИ</strong> (високи R-зъбци).</li><li><strong>В отвеждания I и aVL:</strong> Комплексите са доминиращо <strong>ОТРИЦАТЕЛНИ</strong> (дълбоки S-зъбци).</li><li><strong>Продължителност на QRS:</strong> Обикновено е нормална или съвсем леко удължена (<strong>80-110 ms</strong>).</li></ul><h3>Важно условие за диагностика</h3><p>Диагнозата LPFB е диагноза на изключването. Тя може да бъде поставена само ако са изключени други причини за дясно отклонение на оста:</p><ul><li><strong>Липса на данни за деснокамерна хипертрофия.</strong></li><li><strong>Липса на всякаква друга причина за отклонение на оста надясно</strong> (като белодробен емболизъм или специфични вродени дефекти).</li></ul><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775143151419-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775143151419-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775143151419-image.png\" data-width=\"66\" data-align=\"center\" style=\"width: 1123.32px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Синоатриална проводна система и блокове</h1><p>Синоатриалната проводна система включва SA възела (пейсмейкъра на сърцето) и околната предсърдна тъкан. Нарушенията, при които импулсът се забавя или блокира при излизането си от SA възела към предсърдията, се класифицират в три степени.</p><h2>1. SA блок първа степен</h2><p>Характеризира се с фиксирано забавяне на електрическия импулс при преминаването му от SA възела към предсърдната тъкан.</p><ul><li><strong>ЕКГ критерии:</strong> <strong>Няма видими промени на стандартната ЕКГ.</strong> Тъй като стандартният запис регистрира активност едва при деполяризацията на предсърдията (P-вълната), забавянето <em>преди</em> този момент остава скрито.</li><li><strong>Ключова характеристика:</strong> Връзката е запазена — всеки импулс достига до предсърдията, но със закъснение. На ЕКГ това изглежда като напълно нормален синусов ритъм.</li></ul><h4>Причини:</h4><ul><li><strong>Реверсивни:</strong> Висок вагусов тонус (често при атлети), електролитни нарушения, медикаменти (<strong>бета</strong>-<strong>блокери</strong>, <strong>дигиталис</strong>, <strong>калциеви </strong>антагонисти).</li><li><strong>Структурни:</strong> Исхемия на SA възела, фиброза (свързана със стареенето), възпалителни процеси или Синдром на болния синусов възел (Sick Sinus Syndrome).</li></ul><h4>Клинично значение:</h4><p>Състоянието е доброкачествено и асимптоматично. Тъй като не може да бъде диагностицирано чрез обикновена ЕКГ (изисква се инвазивно изследване), то има по-скоро теоретично значение като начална фаза на синоатриална дисфункция.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>2. SA блок втора степен</h2><p>SA блокът от втора степен се характеризира с периодично прекъсване на проводимостта на синусовия импулс към предсърдния миокард. В резултат на това на електрокардиограмата се наблюдава внезапно отпадане на целия сърдечен цикъл (липсват P-вълна, QRS комплекс и T-вълна). Съгласно класификацията, съществуват две основни форми:</p><h4>Мьобиц тип I (SA Wenckebach)</h4><p>При този тип се наблюдава прогресивно забавяне на синоатриалното провеждане, докато един импулс бъде напълно блокиран в перинодалната тъкан.</p><p><strong>ЕКГ характеристики:</strong></p><ul><li><strong>Прогресивно скъсяване на PP-интервалите:</strong> Преди блокирания удар интервалите между P-вълните се съкращават.</li><li><strong>Пауза (отпаднал цикъл):</strong> Продължителността на паузата е <strong>по-малка</strong> от сбора на два предходни PP-интервала.</li><li><strong>Постпаузален цикъл:</strong> Първият PP-интервал след паузата е по-дълъг от последния PP-интервал преди нея.</li></ul><p><strong>Етиология и патофизиология:</strong></p><ul><li>Обикновено се дължи на повишен вагусов тонус (физиологично при спортисти) или на ефекта на медикаменти с отрицателен дромотропен ефект (дигиталис, бета-блокери). Локализира се в самия SA възел.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775151882758-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775151882758-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 999px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h4>Мьобиц тип II (SA Mobitz II)</h4><p>Характеризира се с внезапно блокиране на синоатриалното провеждане без предхождащи промени в скоростта на импулса.</p><p><strong>ЕКГ характеристики:</strong></p><ul><li><strong>Константни PP-интервали:</strong> Интервалите между P-вълните на проведените удари остават фиксирани и непроменени.</li><li><strong>Математическа пауза:</strong> Продължителността на паузата е <strong>точно кратна</strong> на базовия PP-интервал (еквивалентна на 2, 3 или повече нормални цикъла). </li></ul><p><strong>Патофизиология:</strong></p><ul><li>Обикновено е израз на органично увреждане или фиброза на преходните клетки около синусовия възел. По-често прогресира към по-тежки форми на синусова дисфункция.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775152167248-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775152167248-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775152167248-image.png\" data-width=\"70\" data-align=\"center\" style=\"width: 837.2px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Клинично значение и терапевтичен подход</h3><ul><li><strong>Диагностична прогноза:</strong> Тип II е клинично по-значим поради риск от хемодинамична нестабилност, тежка брадикардия и епизоди на синкоп. Често се асоциира със Синдром на болния синусов възел.</li><li><strong>Лечение:</strong></li><ul><li><strong>При асимптоматични пациенти:</strong> Не се изисква специфична терапия; индицирано е проследяване и преоценка на медикаментозната терапия.</li><li><strong>При симптоматични пациенти:</strong> При наличие на клинични изяви (пресинкоп, синкоп, лесна уморяемост) е необходимо имплантиране на <strong>постоянен пейсмейкър</strong>.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>3. SA блок трета степен (Синоатриален стоп / Complete SA Block)</h2><p>SA блокът от трета степен представлява състояние на пълна липса на проводимост между синусовия възел и предсърдния миокард. При него нито един импулс, генериран в SA възела, не успява да деполяризира предсърдията.</p><h4>Патофизиология и механизъм</h4><p>При трета степен SA блок настъпва пълно прекъсване на изхода на синусовия сигнал:</p><ul><li><strong>Синусов възел:</strong> Продължава да генерира импулси ритмично, но те остават „затворени“ в самия възел.</li><li><strong>Предсърдия и камери:</strong> Тъй като не получават стимул от основния пейсмейкър, се активира <strong>заместващ (escape) ритъм</strong> от по-дистален център, за да се поддържа сърдечната дейност.</li></ul><h3>Етиология<strong>:</strong></h3><ul><li><strong>Остър миокарден инфаркт:</strong> Особено при засягане на <strong>дясната коронарна артерия</strong>, която в 60% от случаите храни SA възела.</li><li><strong>Синдром на болния синусов възел:</strong> Хронична фиброза и дегенерация на пейсмейкърната тъкан.</li><li><strong>Медикаментозна интоксикация:</strong> Предозиране с гликозиди, бета-блокери или антиаритмични средства.</li></ul><h4>ЕКГ характеристики</h4><p>Основният белег на SA блок от трета степен е пълното отсъствие на синусова активност (P-вълни) на записа.</p><ul><li><strong>Липса на P-вълни:</strong> Тъй като импулсът от SA възела не напуска пределите му, предсърдията не се деполяризират по нормалния път.</li><li><strong>Заместващ ритъм:</strong> Наблюдава се ритъм, произхождащ от по-нисък център:</li><ul><li><strong>Атриовентрикуларен (AV) възел:</strong> Най-честият вариант. Характеризира се с тесни QRS комплекси, липса на P-вълни (или ретроградни P-вълни) и честота <strong>40-60 bpm</strong>.</li><li><strong>Идиовентрикуларен ритъм:</strong> Ако AV възелът също не генерира импулс, се активира ритъм от камерите с широки QRS комплекси и честота <strong>&lt; 40 bpm</strong>.</li></ul><li><strong>Диференциална диагноза:</strong> На стандартна ЕКГ блокът от трета степен е неразличим от <strong>синусов арест</strong> (когато SA възелът изобщо престане да генерира импулси). Разликата се установява само чрез електрофизиологично изследване.</li></ul><h4>Клинично значение и лечение</h4><p>Пълният SA блок води до тежка брадикардия, която нарушава хемодинамиката и перфузията на жизненоважни органи.</p><ul><li><strong>Симптоми:</strong> Пациентите проявяват признаци на нисък минутен обем – тежка обща слабост, задух при минимални усилия, замаяност и епизоди на синкоп (Адамс-Стокс атаки).</li><li><strong>Лечение:</strong> </li><ul><li><strong>Спешно:</strong> Приложение на <strong>атропин </strong>или временна електрокардиостимулация при хемодинамична нестабилност.</li><li><strong>Дефинитивно:</strong> Тъй като състоянието често е свързано с необратими дегенеративни промени, основният метод на лечение е имплантирането на <strong>постоянен пейсмейкър</strong>.</li></ul></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Атриовентрикулярна проводна система и блокове</h1><p>Атриовентрикулярната проводна система включва <strong>AV възела</strong>, <strong>снопа на Хис</strong> и неговите <strong>ляв и десен бедрен клон</strong>. Нарушенията в провеждането на импулси между предсърдията и камерите се класифицират в три степени.</p><h2>1. AV блок първа степен</h2><p>Характеризира се с фиксирано забавяне на електрическия импулс при преминаването му през AV възела.</p><ul><li><strong>ЕКГ критерии:</strong> Удължаване на <strong>PR-интервала</strong> над <strong>0,20 секунди</strong> (повече от 5 малки квадратчета).</li><li><strong>Ключова характеристика:</strong> Връзката 1:1 е запазена — всяка P-вълна е последвана от QRS комплекс.</li></ul><h4><strong>Причини:</strong></h4><ul><li><strong>Реверсивни</strong><i>:</i> Висок вагусов тонус, преходна исхемия, медикаменти (бета-блокери, калциеви антагонисти, дигиталис).</li><li><strong>Структурни</strong><i>:</i> Миокарден инфаркт, дегенеративни промени при стареене.</li></ul><h4>Клинично значение:</h4><p>Обикновено е доброкачествено и асимптоматично състояние. Не изисква лечение, но може да бъде индикатор за прогресиращо заболяване на AV възела.</p><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187852670-image.png\" alt=\"image\" data-width=\"100\" data-align=\"center\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187852670-image.png\" data-broken-cleanup-bound=\"1\" style=\"width: 727px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>2. AV блок втора степен</h2><p>AV блокът от втора степен се характеризира с <strong>интермитентен (периодичен) отказ</strong> на атриовентрикуларната проводимост. Резултатът е, че някои P-вълни не са последвани от QRS комплекс. Съществуват две основни форми на този блок:</p><h3>Мьобиц тип I (Möbitz Type I / Wenckebach)</h3><p>При този тип степента на забавяне в AV проводимостта нараства прогресивно с всеки следващ удар, докато един импулс бъде напълно блокиран.</p><p><strong>ЕКГ характеристики:</strong></p><ul><li><strong>Прогресивно удължаване на PR-интервала:</strong> Всеки следващ PR-интервал е по-дълъг от предходния.</li><li><strong>Блокиран импулс:</strong> Накрая се появява една P-вълна, след която <strong>липсва QRS комплекс</strong> (единичен изпуснат удар).</li><li><strong>Рестарт на цикъла:</strong> След паузата PR-интервалът се скъсява до първоначалната си (най-кратка) дължина и цикълът започва отново.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187943003-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187943003-image.png\" data-width=\"100\" data-align=\"center\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187943003-image.png\" data-broken-cleanup-bound=\"1\" style=\"width: 832px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\"></p><p><strong>Патофизиология и локализация:</strong></p><ul><li><strong>Място на блока:</strong> Почти винаги се дължи на нарушение в самия <strong>AV възел</strong>.</li><li><strong>Клиничен контекст:</strong> Обикновено е доброкачествен. Може да се наблюдава при деца, тренирани атлети и хора с висок вагусов тонус (особено по време на сън).</li><li><strong>Остри състояния:</strong> Може да възникне по време на остър миокарден инфаркт поради исхемия на AV възела или повишен вагусов тонус, но обикновено е преходен.</li></ul><p><strong>Лечение:</strong></p><ul><li>Обикновено не е необходимо лечение.</li><li><strong>Симптоматични случаи:</strong> При наличие на симптоми (замаяност, умора), интравенозното приложение на <strong>атропин</strong> или <strong>изопротеренол</strong> обикновено подобрява проводимостта временно.</li><li><strong>Постоянен пейсмейкър:</strong> Изисква се само ако блокът е хроничен, симптоматичен и не се коригира след премахване на утежняващите фактори.</li></ul><h3>Мьобиц тип II (Möbitz Type II)</h3><p>Характеризира се с внезапна и епизодична загуба на AV проводимост <strong>без</strong> предварително удължаване на PR-интервала.</p><p><strong>ЕКГ характеристики:</strong></p><ul><li><strong>Фиксиран PR-интервал:</strong> За разлика от Тип I, тук няма прогресивно удължаване. PR-интервалите на проведените удари са константни.</li><li><strong>Внезапно отпадане:</strong> QRS комплексът изчезва внезапно след P-вълна.</li><li><strong>Високостепенен (High-grade) AV блок:</strong> Ако две или повече последователни P-вълни не са последвани от QRS комплекси.</li></ul><p><strong>Патофизиология и локализация:</strong></p><ul><li><strong>Място на блока:</strong> Обикновено се причинява от блок <strong>отвъд AV възела</strong> (в снопа на Хис или дистално в системата на Пуркиние).</li><li><strong>QRS морфология:</strong> Поради дисталната локализация, QRS често е разширен и показва модел на <strong>ляв или десен бедрен блок</strong>.</li><li><strong>Етиология:</strong> Често е резултат от обширен миокарден инфаркт (засягащ септума) или хронична дегенерация на системата на Хис-Пуркиние.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188094124-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188094124-image.png\" data-width=\"100\" data-align=\"center\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188094124-image.png\" data-broken-cleanup-bound=\"1\" style=\"width: 721px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\"><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188510527-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188510527-image.png\" data-width=\"100\" data-align=\"center\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188510527-image.png\" data-broken-cleanup-bound=\"1\" style=\"width: 726px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\"></p><p><strong>Клинично значение и лечение:</strong></p><ul><li><strong>Опасност:</strong> Този тип блок е много по-опасен от Мьобиц тип I, тъй като може да прогресира до <strong>пълен (трета степен) AV блок</strong> внезапно и без предупреждение.</li><li><strong>Прогноза:</strong> Обикновено показва тежко заболяване на проводната система.</li><li><strong>Лечение:</strong> Поставянето на <strong>постоянен пейсмейкър</strong> обикновено е задължително, дори при асимптоматични пациенти, поради риска от внезапна прогресия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>3. AV блок трета степен (Third-Degree / Complete Heart Block)</h2><p><strong></strong>AV блокът от трета степен, известен още като <strong>пълен сърдечен</strong>, представлява състояние на <strong>пълна липса на проводимост</strong> между предсърдията и камерите. При него нито един импулс от предсърдията не достига до камерите.</p><h3><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188965414-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188965414-image.png\" data-width=\"100\" data-align=\"center\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774188965414-image.png\" data-broken-cleanup-bound=\"1\" style=\"width: 854px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\"><em></em>Патофизиология и Механизъм</h3><p>В основата на трета степен AV блок стои пълна <strong>електромеханична дисоциация</strong> на сърцето:</p><ul><li><strong><p><strong>Предсърдна активност</strong></p>:</strong> <p>Предсърдията се деполяризират автономно под влияние на синусовия (SA) възел или друг предсърден пейсмейкър.</p></li><li><strong><p>Камерна активност:</p></strong> <p>Поради липсата на антеградно провеждане, камерите се активират от независим <strong>ектопичен заместващ център</strong> (escape rhythm), разположен дистално от мястото на блока.</p></li><li><strong>Етиология:&nbsp;</strong>При възрастни пациенти най-честите причини са:</li><ul><li><strong>Остър миокарден инфаркт:</strong> <p>Обширна исхемия, водеща до некроза на проводната тъкан (често при преден инфаркт със засягане на снопа на Хис).</p></li><li><strong></strong><p><strong>Идиопатична фиброза:</strong> Хронични дегенеративни процеси на проводната система.</p></li><li><p><strong>Ятрогенни фактори:</strong> След сърдечни операции или катетърни аблации.</p><br></li></ul></ul><h3><em></em>ЕКГ Характеристики</h3><p>Фундаменталният белег на това състояние е <strong>AV дисоциацията</strong>. Основните диагностични критерии са:</p><ul><li><strong>Липса на зависимост между P-вълни и QRS комплекси:</strong> Връзката между предсърдната и камерната активност е напълно прекъсната; PR-интервалът е променлив и не подлежи на измерване.</li><li><strong></strong><p><strong>Регулярен предсърден ритъм (P-P интервали):</strong> P-вълните се появяват ритмично с честота, по-висока от тази на камерите.</p></li><li><strong>Регулярен камерен ритъм (R-R интервали):</strong> QRS комплексите са ритмични, но с изразена брадикардия.</li></ul><p><strong>Морфологията на QRS комплекса зависи от локализацията на заместващия център:</strong></p><ul><ul><li><strong>Проксимален (възлово-заместващ) ритъм:</strong> Възниква в AV възела. Характеризира се с тесни QRS комплекси (<strong>&lt; 0,12 сек</strong>) и честота <strong>40–60 bpm</strong>.</li><li><strong>Дистален (идиовентрикуларен) ритъм:</strong> Възниква в системата на Хис-Пуркиние. Характеризира се с широки, деформирани QRS комплекси (<strong>≥ 0,12 сек</strong>) и ниска честота <strong>&lt; 40&nbsp;</strong><strong>bpm</strong>.</li></ul></ul><h3>Клинично значение</h3><p>Критичното понижение на сърдечната честота води до значително редуциране на минутния обем и системна хипоперфузия.</p><ul><li><strong>Клинична картина: </strong>Пациентите проявяват симптоми на нисък дебит – изразена <strong>астенодинамия </strong>(лесна уморяемост), <strong>вертиго </strong>(замаяност) или <strong>синкоп</strong>.</li></ul><h3>Терапевтичен подход</h3><p>Пълният AV блок представлява спешно състояние в кардиологията и изисква поетапен подход на лечение:</p><ul><li><strong>Остра фаза:</strong></li><ul><li><strong>Медикаментозен „мост“:</strong> Прилагане на <strong>Атропин </strong>(интравенозно) за временно ускоряване на ритъма. При липса на ефект се започва инфузия на <strong>Адреналин </strong>или <strong>Изопреналин</strong>.</li><li><strong>Временна електрокардиостимулация (Пейсинг):</strong> Използване на външен апарат за подаване на ритмични електрически импулси към сърцето, т.е. <strong>временен пейсмейкър</strong>.</li></ul><li><strong>Дефинитивно лечение:</strong><strong> </strong></li><ul><li>Имплантиране на <strong>постоянен пейсмейкър</strong> е абсолютно показано в почти всички случаи поради високия риск от внезапна сърдечна смърт.</li></ul></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Патологични Q-зъбци при инфаркт на миокарда</h1><p>Внезапната оклузия на коронарна артерия обикновено води до синдром, известен като <strong>миокарден инфаркт с елевация на ST-сегмента (STEMI)</strong>. Когато това се случи, в продължение на часове се развива поредица от аномалии на ST-сегмента и T-вълната. Освен ако не се постигне бърза реперфузия на оклудираната артерия, настъпва необратима некроза на сърдечния мускул, обслужван от този съд, което се отбелязва с появата на <strong>патологични Q-зъбци</strong> в QRS комплекса.</p><h2>Физиологични срещу Патологични Q-зъбци</h2><p>Нормално е в някои ЕКГ отвеждания да се появяват малки начални Q-зъбци (напр. от септална деполяризация в <strong>V6</strong> и <strong>aVL</strong>).</p><ul><li><strong>Физиологични Q-зъбци:</strong> Кратка продължителност (&lt; 0,04 sec) и ниска амплитуда (&lt; 25% от общата височина на QRS).</li><li><strong>Патологични Q-зъбци:</strong> По-изразени, със следните критерии:</li><ul><li><strong>Ширина:</strong>  ≥ 1 малко квадратче (0,04 sec).</li><li><strong>Дълбочина:</strong>  ≥ 25% от общата височина на QRS комплекса.</li></ul></ul><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774017399637-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-20/text-editor-images/2026/03/1774017399637-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 475px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><h2>Механизъм на образуване</h2><p>Патологичните Q-зъбци се появяват в отвежданията над инфарктната тъкан, тъй като некротичният мускул е електрически „ням“ и не генерира сили. ЕКГ електродът над тази зона регистрира електрическите токове от здравата тъкан в срещуположните части на камерата. Тези токове са насочени <strong>далеч</strong> от инфаркта и записващия електрод, което изписва отрицателно отклонение. Q-зъбците са постоянно доказателство за прекаран STEMI и рядко изчезват.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774183186918-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774183186918-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774183186918-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1130px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h2>Локализация и диагностични особености</h2><p>Групирането на отвежданията с патологични Q-зъбци отразява анатомичното място на инфаркта.</p><ul><li><strong>Заден миокарден инфаркт:</strong> Тъй като стандартните електроди не се поставят на гърба, тук не се виждат типични Q-зъбци. Вместо това се разчита на огледалния образ в <strong>V1 и V2</strong>:</li><ul><li><strong>Високи R-зъбци</strong>&nbsp;в V1 и V2 са еквивалент на патологични Q-зъбци при заден МИ.</li><li><em>Диференциална диагноза:</em> Деснокамерната хипертрофия също дава високи R в V1/V2, но тя причинява отклонение на оста надясно, което липсва при задния МИ.</li></ul><li><strong>Важни правила:</strong></li><ul><li>Q-зъбец само в <strong>едно единствено отвеждане</strong> не е диагностичен за инфаркт. Те трябва да са в съответните групи (напр. ако има Q в III, трябва да има и в II или aVF).</li><li>Q-зъбците в <strong>aVR</strong> се игнорират, тъй като там векторите нормално са насочени далеч от електрода.</li><li>При наличие на <strong>ляв бедрен блок</strong>, Q-зъбците обикновено не са полезни за диагноза на инфаркт поради силно променената деполяризация.</li></ul></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775148708876-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775148708876-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775148708876-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 939px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Аномалии на ST-сегмента и T-вълната</h1><h2>Преходна миокардна исхемия</h2><p>Сред най-важните аномалии на ST-сегментите и T-вълните са тези, свързани с коронарна болест на сърцето. Тъй като камерната реполяризация е изключително чувствителна към миокардната перфузия, обратимите отклонения на ST-сегментите и T-вълните са чести по време на преходни епизоди на миокардна исхемия. Те обикновено се манифестират като:</p><ul><li><strong>Депресия на ST-сегмента</strong></li><li><strong>Инверсия на T-вълната</strong> (или и двете едновременно).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остър миокарден инфаркт с ST-елевация (STEMI)</h2><p>Патологичните Q-зъбци са свързани с миокардния инфаркт, но те не позволяват разграничаване между остро събитие и МИ, настъпил преди седмици или години. Острият STEMI обаче води до характерна времева последователност от промени в ST и T вълните:</p><ol><li><strong>Ранна фаза:</strong> Първата аномалия е <strong>елевация на ST-сегмента</strong>, често придружена от <strong>изострена (peaked)</strong> T-вълна. На този ранен етап миокардните клетки са все още жизнеспособни и Q-зъбци все още не са се образували.</li><li><strong>Реперфузия:</strong> При пациенти с успешна остра коронарна реперфузия (чрез фибринолитична терапия или перкутанна коронарна интервенция), ST-сегментите се връщат към изоелектричната линия и следващите промени не настъпват.</li><li><strong>Еволюция при липса на реперфузия:</strong> В рамките на няколко часа смъртта на миоцитите води до загуба на амплитудата на R-зъбеца и започват да се изписват патологични Q-зъбци в отвежданията над зоната на инфаркта.</li><li><strong>Първи 1-2 дни:</strong> ST-сегментите остават елевирани, T-вълната се инвертира, а Q-зъбецът става по-дълбок.</li><li><strong>След няколко дни:</strong> ST-елевацията се връща към базовата линия, но T-вълните остават инвертирани.</li><li><strong>Седмици/месеци по-късно:</strong> ST-сегментът и T-вълната обикновено се нормализират, но <strong>патологичните Q-зъбци персистират</strong> като постоянен маркер за инфаркта.</li><ul><li><em>Забележка:</em> Ако ST-елевацията остане след няколко седмици, това вероятно показва образуването на изпъкнал фиброзен цикатрикс (<strong>камерна аневризма</strong>).</li></ul></ol><ul><li><strong>Реципрочни промени:</strong></li><ul><li>Еволюционните промени се записват от отвежданията над зоната на инфаркта, но типично се наблюдават <strong>реципрочни промени</strong> в срещуположните отвеждания. </li></ul></ul><ul><ul><li><em>Пример:</em> При остър антеросептален МИ има ST-елевация в V1 и V2, докато едновременно с това в долните отвеждания (II, III и aVF) може да се запише реципрочна ST-депресия.</li></ul></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774185399622-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774185399622-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 584px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Миокарден инфаркт без ST-елевация (NSTEMI)</h2><p>Не всички остри миокардни инфаркти водят до ST-елевация и потенциално развитие на Q-зъбци. Един по-ограничен тип инфаркт, известен като <strong>остър миокарден инфаркт без ST-елевация (NSTEMI)</strong>, обикновено е резултат от остър, частично оклузивен коронарен тромб.</p><p>При такива инфаркти в отвежданията над инфарктния миокард се появява <strong>ST-сегментна депресия</strong> и/или <strong>инверсия на T-вълната</strong>, вместо ST-елевация.</p><p>Степента на миокардно увреждане при тази форма на инфаркт е по-малка, отколкото при STEMI, като често включва само <strong>субендокардните слоеве</strong> на миокарда. В резултат на това <strong>не се развиват патологични Q-зъбци</strong>, тъй като останалите жизнеспособни клетки са в състояние да генерират известна електрическа активност.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Други причини за аномалии</h2><p>Освен миокардна исхемия и инфаркт, съществуват няколко други причини за аномалии на ST-сегмента и T-вълната, които са резултат от промени в реполяризацията на миоцитите. Най-често срещаните от тях са илюстрирани на следващата фигура:</p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774184028794-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774184028794-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1086px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">БРАДИАРИТМИИ</h1><p>Нормалната сърдечна честота в покой, произтичаща от повтарящата се деполяризация на синусовия възел, варира от <strong>60 до 100 bpm</strong>. Брадиаритмиите са ритми, при които сърдечната честота е <strong>под 60 bpm</strong>. Те възникват поради нарушения в образуването на импулси или нарушена проводимост на импулсите.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: left\">Синусов възел</h1><h2>Синусова брадикардия</h2><p>Синусовата брадикардия представлява забавяне на нормалния сърдечен ритъм в резултат на намалена честота на генериране на импулси от SA възел до честота <strong>под 60 bpm</strong>.</p><ul><li><strong>Физиологична:</strong> В покой или по време на сън е нормална и доброкачествена находка. Високо тренираните атлети често имат повишен вагусов тонус, което води до асимптоматична брадикардия. Преходни периоди на висок вагусов тонус могат да се появят и като рефлексен отговор на <strong>болка или страх</strong>.</li><li><strong>Патологична:</strong> Може да се дължи на:</li><ul><li><strong>Интринзитни фактори:</strong> Остаряване, исхемична болест на сърцето или кардиомиопатия.</li><li><strong>Екстринзитни фактори:</strong> Медикаменти (напр. <strong>бета-блокери</strong> и някои калциеви антагонисти) или метаболитни причини (напр. <strong>хипотиреоидизъм</strong>).</li></ul></ul><p><strong>Клинична картина:</strong> Леката брадикардия обикновено е асимптоматична. Изразеното забавяне намалява минутния обем и води до умора, замаяност, объркване или синкоп.</p><h2>Синдром на болния синусов възел</h2><p>Интринзитната дисфункция на синусовия възел, която причинява периоди на неадекватна брадикардия, е известна като <strong>синдром на болния синусов възел</strong>. Това състояние често предизвиква симптоми като замаяност, объркване или синкоп. </p><p><strong>Лечение:</strong></p><ul><li><strong>Спешно/Временно:</strong> Пациентите със симптоматична синусова брадикардия могат да бъдат лекувани с интравенозни антихолинергични средства (напр. <strong>atropine</strong>) или бета-адренергични агенти (напр. <strong>isoproterenol</strong>), които временно ускоряват сърдечната честота. </li><li><strong>Хронично:</strong> Ако проблемът е хроничен и не се коригира чрез премахване на утежняващите фактори, е необходимо поставянето на <strong>постоянен пейсмейкър</strong>.</li></ul><h2>Синдром брадикардия-тахикардия</h2><p>SSS е често срещан при възрастни пациенти, които също са податливи на суправентрикуларни тахикардии, най-често предсърдно мъждене. Тази комбинация е известна като <strong>синдром брадикардия-тахикардия</strong>.</p><ul><li><strong>Механизъм:</strong> Смята се, че е резултат от предсърдна фиброза, която уврежда функцията на SA възела и предразполага към предсърдно мъждене и трептене. </li><li><strong>Динамика:</strong> По време на тахиаритмията настъпва потискане на SA възела. Когато тахикардията спре, може да последва период на дълбока синусова брадикардия. </li><li><strong>Лечение:</strong> Обикновено изисква комбинация от <strong>антиаритмична лекарствена терапия</strong> (за потискане на тахиаритмиите) плюс <strong>постоянен пейсмейкър</strong> (за предотвратяване на брадикардията).</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187476727-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187476727-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 716px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h2>Заместващи ритми (Escape Rhythms)</h2><p>Клетките в AV възел и системата на Хис-Пуркиние притежават способност за автоматизъм, но обикновено имат по-ниска честота на генериране на импулси от синусовия възел и затова са потиснати по време на нормален синусов ритъм. Ако обаче активността на SA възела се наруши или има блок в провеждането, се появяват <strong>заместващи ритми</strong> от по-дисталните латентни центрове.</p><h3>1. Нодален заместващ ритъм (Junctional Escape Rhythm)</h3><p>Възниква от AV възела или проксималната част на снопа на Хис.</p><ul><li><strong>Характеристики:</strong> Нормален, тесен QRS комплекс.</li><li><strong>Честота:</strong> 40 до 60 bpm.</li><li><strong>P-вълни:</strong> QRS комплексите <strong>не са</strong> предшествани от нормални P-вълни, тъй като импулсът възниква под предсърдията. Могат да се наблюдават <strong>ретроградни P-вълни</strong> (импулсът се разпространява назад към предсърдията). Те обикновено следват QRS комплекса и са отрицателни в периферните отвеждания <strong>II, III и aVF</strong>.</li></ul><h3>2. Камерен заместващ ритъм (Ventricular Escape Rhythm)</h3><ul><li><strong>Честота:</strong> Много по-ниска (<strong>30 до 40 bpm</strong>).</li><li><strong>Характеристики:</strong> Разширени QRS комплекси. </li><li><strong>Механизъм:</strong> Комплексите са широки, защото камерите не се деполяризират чрез нормалното едновременно провеждане по бедрените клонове, а от по-дистална точка.</li><li><strong>Морфология:</strong> Зависи от мястото на произход:</li><ul><li>Произход от <strong>левия бедрен клон</strong> -&gt; QRS с конфигурация на десен бедрен блок.</li><li>Произход от <strong>десния бедрен клон</strong> -&gt; QRS с конфигурация на лев бедрен блок.</li><li>Произход от <strong>самия камерен миокард</strong> (още по-дистално) -&gt; изключително широки QRS комплекси, тъй като провеждането е извън системата на Пуркиние.</li></ul></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187646659-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774187646659-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 778px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Клинично значение</h3><p>Заместващите ритми са <strong>защитни резервни механизми</strong>, които поддържат сърдечната честота и минутния обем, когато синусовият възел или нормалното AV провеждане откажат. Клиничните находки и лечението са идентични с тези при SSS.</p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">ТАХИАРИТМИИ</h1><p>Тахиаритмия е налице, когато сърдечната честота е <strong>≥ 100 bpm</strong> за три или повече последователни удара. Те произтичат от три основни механизма:</p><h2>1. Reentry<br></h2><p>Reentry е механичен процес, при който електрическият импулс не се изгасва след активиране на сърцето, а се затваря в безкраен цикъл (верига), който стимулира камерите или предсърдията отново и отново.</p><h3>Трите задължителни условия за Reentry:</h3><p>За да възникне, трябва да са изпълнени три условия едновременно:</p><ol><li><strong>Два паралелни пътя за провеждане:</strong> Наличие на две трасета (напр. в AV възела или около цикатрикс от инфаркт), които са свързани в началото и в края си.</li><li><strong>Еднопосочен блок:</strong> Импулсът трябва да бъде блокиран в единия път (обикновено по-бързия), но да успее да премине по другия (бавния).</li><li><strong>Забавено провеждане:</strong> Импулсът трябва да се движи достатъчно бавно по отворения път, така че блокираният път да има време да се реполяризира и да приеме импулса, когато той се върне отзад.</li></ol><h3>Клинично значение</h3><p>Reentry е механизмът зад:</p><ul><li><strong>Предсърдно трептене:</strong> Голяма верига около трикуспидалната клапа.</li><li><strong>AVNRT:</strong> Малка верига в самия AV възел (бърз и бавен път).</li><li><strong>WPW синдром:</strong> Верига между нормалната система и допълнителната връзка.</li><li><strong>Камерна тахикардия:</strong> Верига около цикатрикс от стар миокарден инфаркт.</li></ul><h2>2. Повишен автоматизъм</h2><p>Автоматизмът е способността на определени сърдечни клетки спонтанно да генерират електрически импулс. Повишеният автоматизъм възниква, когато клетките започнат да се деполяризират по-бързо от нормалното или когато клетки, които обикновено не го правят, поемат ролята на пейсмейкър.</p><h3>Причини за повишен автоматизъм</h3><p>Този механизъм често е резултат от метаболитни или химични промени, които дразнят сърцето:</p><ul><li><strong>Висок симпатиков тонус:</strong> Адреналин, стрес, физическо натоварване.</li><li><strong>Електролитни нарушения:</strong> Хипокалиемия.</li><li><strong>Исхемия:</strong> Клетките в зоната на инфаркт стават електрически нестабилни и започват да „стрелят“ сами.</li><li><strong>Метаболитни състояния:</strong> Хипоксия или ацидоза.</li><li><strong>Лекарства:</strong> Атропин или токсичност от медикаменти.</li></ul><h3>Клинични примери</h3><p>Повишеният автоматизъм е в основата на:</p><ul><li><strong>Синусова тахикардия.</strong></li><li><strong>Ектопични предсърдни ритми:</strong> Огнище в предсърдията, различно от SA-възела, „надделява“ и диктува ритъма.</li><li><strong>Идиовентрикуларен ритъм:</strong> Когато камерите поемат контрола при много нисък пулс (защитен механизъм).</li><li><strong>Някои форми на камерна тахикардия:</strong> Особено в ранната фаза на остър инфаркт.</li></ul><h3>3. Тригерна активност</h3><p>Тригерната активност е специфичен механизъм за възникване на аритмии, при който необичайни електрически колебания се „отключват“ (trigger) от предходен сърдечен удар. Тези колебания се наричат <strong>следдеполяризации</strong>.</p><h3>Видове следдеполяризации</h3><h4>1. Ранни следдеполяризации</h4><ul><li><strong>Кога възникват:</strong> По време на фаза 2 или 3 на акционния потенциал (преди клетката да се е възстановила напълно).</li><li><strong>Причина:</strong> Удължаване на акционния потенциал (дълъг QT-интервал).</li><li><strong>Клинична връзка:</strong> Това е основният механизъм за фаталната аритмия <strong>Torsades de Pointes</strong>.</li><li><strong>Провокатори:</strong> Лекарства, удължаващи QT, хипокалиемия, брадикардия.</li></ul><h4>2. Късни следдеполяризации</h4><ul><li><strong>Кога възникват:</strong> Веднага след приключване на пълната реполяризация (началото на фаза 4).</li><li><strong>Причина:</strong> Вътреклетъчно претоварване с калций.<span class=\"vlist\" style=\"height: 0.8141em\"><span class=\"\" style=\"top: -3.063em; margin-right: 0.05em\"><br></span></span></li><li><strong>Клинична връзка:</strong> Свързват се с <strong>дигиталисова токсичност</strong>&nbsp;и силна симпатикусова стимулация (стрес/адреналин).</li></ul><blockquote><strong>Запомни:</strong> Тригерната активност винаги е „зависима“ от предходния ритъм. Ако спрем базовия ритъм или променим честотата му, обикновено спираме и тригерните удари.</blockquote><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Суправентрикуларни тахиаритмии</h1><p>Тези аритмии възникват в предсърдията или AV възела. <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774189137437-image.png &quot;width=100%&quot;)\" id=\"note-1774189139295-0\">Обща схема</span></strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>1. Синусова тахикардия</h2><p>Характеризира се с честота на генериране на импулси от SA възела <strong>≥ 100 bpm</strong> (обикновено между 100 и 180 bpm).</p><ul><li><strong>ЕКГ Характеристики:</strong></li><ul><li>Нормални P-вълни и нормални QRS комплекси.</li><li>Ритъмът е правилен.</li></ul><li><strong>Етиология:</strong></li><ul><li><strong>Физиологична:</strong> Нормален отговор при физическо натоварване.</li><li><strong>Патологична:</strong> Резултат от симпатикусова стимулация при състояния като фебрилитет, хипоксемия, хипертиреоидизъм, хиповолемия и анемия.</li></ul><li><strong>Лечение:</strong> Тъй като обикновено е симптом на друго състояние, лечението трябва да бъде насочено към <strong>основната причина</strong>.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774189225526-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774189225526-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 792px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>2. Предсърдни екстрасистоли (Atrial Premature Beats - APBs)</h2><p>Предсърдните екстрасистоли са често срещани както при здрави, така и при болни сърца. Те произлизат от ектопично огнище в предсърдията извън синусовия възел.</p><ul><li><strong>Механизъм:</strong> Възникват чрез автоматизъм или reentry и често се обострят от симпатикусова стимулация. Обикновено са асимптоматични, но могат да причинят усещане за палпитации.</li><li><strong>ЕКГ характеристики:</strong> На ЕКГ се появява <strong>по-ранна от очакваното P-вълна</strong> с анормална форма. Това е така, защото импулсът не произлиза от SA възела, което води до необичайно провеждане през предсърдията. </li><li><strong>Камерно провеждане:</strong> QRS комплексът, който следва P-вълната, обикновено е нормален и наподобява този при синусов ритъм, тъй като камерното провеждане не е увредено.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774189481033-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774189481033-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774189481033-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 722px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h4>Специфични форми на APB според времето на възникване:</h4><p><strong>Блокиран APB:</strong></p><p>Ако анормалното предсърдно огнище се активира много скоро след предходния удар, импулсът може да завари AV възела в рефрактерен период. Резултатът е блокиран импулс, който не се провежда до камерите. В този случай преждевременната P-вълна не е последвана от QRS комплекс.</p><p><strong>APB с аберантно провеждане:</strong></p><p>Ако ектопичното огнище се активира малко по-късно в диастолата, импулсът може да премине през AV възела, но да завари части от системата на Хис-Пуркиние все още в рефрактерност. Вследствие на това импулсът се провежда по-бавно от нормалното, което произвежда <strong>анормално широки QRS комплекси</strong>.</p><h4>Лечение и превенция на APB</h4><p>Предсърдните екстрасистоли изискват лечение само ако са симптоматични. Тъй като кофеинът, алкохолът и адренергичната стимулация (напр. емоционален стрес) предразполагат към тях, е важно тези фактори да бъдат овладени. Ако е необходимо медикаментозно лечение, <strong>бета-блокерите</strong> са предпочитаното начално средство.</p><blockquote><strong>Ключов детайл:</strong> При блокиран APB често се прави грешка да се диагностицира синусова пауза или AV блок, но внимателното вглеждане в предходната T-вълна често разкрива скрита в нея деформирана P-вълна.</blockquote><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>3. Предсърдно трептене (Atrial Flutter)</h2><p>Предсърдното трептене е по-рядко от AVNRT и обикновено се среща при пациенти с подлежаща сърдечна патология, макар и рядко да се наблюдава при здрави сърца.</p><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774190124780-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774190124780-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 793px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Механизъм и Честота</h3><ul><li><strong>Механизъм:</strong> Re-entry по фиксирана анатомична верига в дясното предсърдие (най-често около трикуспидалната клапа и каво-трикуспидалния истмус).</li><li><strong>Предсърдна честота:</strong> Строго ритмична, диапазон <strong>250–350</strong> bpm.</li><li><strong>AV-провеждане:</strong> AV-възелът не може да проведе всеки импулс (физиологичен блок). Най-често е <strong>2:1</strong> (камерна честота 150 bpm).</li><li><strong>Вагусови маневри:</strong> Не спират аритмията, но засилват AV-блока (напр. от 2:1 на 4:1), което <p>позволява по-добра визуализация на F-вълните.</p></li></ul><h3>ЕКГ Диагностика (F-вълни)</h3><p>Поради високата честота липсва изоелектрична линия – тя постоянно се издига и спада (\"зъби на трион\").</p><h4>А. Античасовникова ре-ентри (Типична – 90%)</h4><ul><li><strong>Отвеждания II, III, aVF:</strong> Негативни F-вълни (трионът сочи надолу).</li><li><strong>Отвеждане V1:</strong> Позитивни F-вълни (наподобяват P-вълни).</li></ul><h4>Б. Часовникова ре-ентри (Рядка)</h4><ul><li><strong>Отвеждания II, III, aVF:</strong> Позитивни F-вълни.</li><li><strong>Отвеждане V1:</strong> Широки, негативни F-вълни.</li></ul><h3>Клинична картина и рискове</h3><ul><li><strong>Симптоми:</strong> Зависят от камерната честота. При 100 bpm пациентът може да е асимптоматичен, но по-високите честоти причиняват палпитации, задух или слабост.</li><li><strong>Парадоксален ефект на лекарствата:</strong> Антиаритмици, които забавят предсърдната честота (напр. от 280 на 220 bpm), могат да скъсят времето за възстановяване на AV-възела и да доведат до опасно <strong>1:1 провеждане</strong> (ускоряване на камерите до 220 bpm).</li><li><strong>Тромбоемболичен риск:</strong> Висок риск от образуване на предсърдни тромби и инсулт.</li></ul><h3>Лечебни подходи</h3><ol><li><strong>Електрическо кардиоверзио:</strong> Най-бърз метод за възстановяване на синусов ритъм при симптоматични пациенти.</li><li><strong>Rapid Atrial Stimulation (Burst pacing):</strong> Прекъсване на трептенето чрез бърза стимулация с пейсмейкър (често след сърдечна хирургия).</li><li><strong>Фармакологична терапия:</strong></li><ul><li><strong>Контрол на честотата:</strong> Бета-блокери, калциеви антагонисти (verapamil) или digoxin за увеличаване на AV-блока.</li><li><strong>Ритъмен контрол:</strong> Антиаритмици от клас IA, IC или III.</li></ul><li><strong>Катетърна аблация:</strong> Дефинитивно лечение чрез обгаряне на част от re-entry веригата.&nbsp;</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">4. Предсърдно мъждене (Atrial Fibrillation)</h2><p style=\"text-align: center\"><em>Най-честата и клинично значима устойчива аритмия</em></p><em><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774190246895-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774190246895-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774190246895-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 834px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></em><h3>Патофизиология и Механизъм</h3><p>Предсърдното мъждене е състояние на <strong>пълен електрически хаос</strong>. За разлика от трептенето (където има една голяма re-entry верига), тук <strong>стотици микро-re-entry вериги</strong> се въртят непредсказуемо из предсърдията.</p><ul><li><strong>Предсърдна честота:</strong> <p>Екстремно висока електрическа активност (<strong>350–600 bpm</strong>), при която липсва ефективна предсърдна систола.</p></li><li><strong>Огнища (Triggers):</strong> <p>Инициира се от високочестотни разряди, възникващи в миокардните проксимални сегменти на <strong>белодробните вени </strong>при вливането им в лявото предсърдие.</p></li><li><strong>AV-провеждане:</strong> <p>Атриовентрикуларният възел упражнява филтрираща функция върху хаотичните импулси, като провежда само част от тях към камерите през променливи интервали.</p></li></ul><h3>ЕКГ Характеристики</h3><p>Диагнозата се поставя чрез комбинация от два ключови белега:</p><ol><li><strong>Абсолютна аритмия:</strong> Пълна нерегулярност на камерния отговор (променливи RR-интервали) без повтарящ се модел.</li><li><strong></strong><p><strong>Липса на дискретни P-вълни: </strong>Отсъствие на организирана предсърдна деполяризация преди всеки QRS комплекс.</p> </li></ol><p><strong>Допълнителни находки:</strong></p><ol><li><strong>Фибрилаторни (f) вълни:</strong> Изоелектричната линия е заменена от нискоамплитудни, хаотични колебания с висока честота.</li><li><p><strong>Камерен отговор:</strong> При липса на терапия камерната честота обикновено варира между <strong>120 и 180 bpm</strong>.</p></li></ol><blockquote><strong>Важно за диференциалната диагноза:</strong> Силна синусова аритмия или предсърдно трептене с вариабилен блок също могат да изглеждат неритмични, но при AF липсата на P-вълни е водеща.</blockquote><h3>Клинично значение и Рискове</h3><ul><li><strong>Симптоми:</strong> Палпитации, задух, гръдна болка или замайване. Много пациенти (особено възрастни) могат да са напълно асимптоматични.</li><li><strong>Нарушен сърдечен дебит:</strong> Загубата на организирано предсърдно съкращение намалява пълненето на камерите. Това може да доведе до хипотония и белодробен застой.</li><li><strong>Тромбоемболизъм (Инсулт):</strong> Стазата на кръвта в предсърдията (особено в <strong>ухото на лявото предсърдие</strong>) води до образуване на тромби. Емболизацията им е водеща причина за исхемичен инсулт.</li><li><strong>Предразполагащи фактори:</strong> Хипертония, коронарна болест, клапни пороци (митрална стеноза), затлъстяване, алкохол (\"holiday heart\"), тиреотоксикоза и сънна апнея.</li></ul><h3>Терапевтичен алгоритъм</h3><p>Критичната граница от 48 часа определя стратегията за превенция на тромбоемболични събития, тъй като след този период рискът от формиране на интраатриални тромби нараства значително.</p><h4><strong>1. Продължителност под 48 часа</strong></h4><p>При доказана давност на епизода под 48 часа рискът от системна емболизация е нисък, което позволява ранна интервенция.</p><ul><li><strong>Ритъмен контрол:</strong> Допустимо е извършването на <strong>незабавно кардиоверзио </strong>(електрическо или медикаментозно).</li><li><strong>Антикоагулация:</strong> <p>Започва се веднага (обикновено с хепарин или НМХ), като след процедурата се преценява дали да продължи дългосрочно въз основа на <span class=\"editor-note\" data-note=\"| Буква | Критерий | Точки |\n| :--- | :--- | :--- |\n| **C** | Сърдечна недостатъчност | 1 |\n| **H** | Хипертония | 1 |\n| **A₂** | Възраст ≥ 75 години| **2** |\n| **D** | Захарен диабет| 1 |\n| **S₂** | Предишен инсулт или ТИА| **2** |\n| **V** | Съдово заболяване | 1 |\n| **A** | Възраст 65–74 години| 1 |\n| **Sc** | Пол - женски| 1 |\" id=\"note-1775202628829-1\">CHA2DS2-VASc</span> скора.</p></li><li><strong>Хемодинамична нестабилност:</strong> При наличие на белодробен оток, хипотония или остра коронарна исхемия се инициира спешно електрическо кардиоверзио, независимо от времевия прозорец.</li></ul><h4><strong>2. Продължителност над 48 часа или неизвестна</strong></h4><p>Рискът от наличие на тромб е висок. Кардиоверзиото в този момент може да \"изхвърли\" тромба и да причини инсулт.</p><ul><li><strong>Стандартна стратегия:&nbsp;</strong>Ефективна антикоагулация в продължение на най-малко <strong>3 седмици</strong> преди възстановяване на ритъма.</li><li><strong>Алтернативна стратегия:&nbsp;</strong><p>Извършване на <strong>Трансезофагеална ехокардиография </strong>(<strong>ТЕЕ</strong>). Ако ТЕЕ потвърди, че няма тромби, може да се премине към кардиоверзио веднага.</p></li><li><strong>Честотен контрол:</strong> Медикаментозно регулиране на камерната честота (бета-блокери, калциеви антагонисти) по време на антикоагулационния период.</li><li><p><strong>След процедурата:</strong> Задължителна антикоагулация за поне 4 седмици след кардиоверзиото, независимо от резултата.</p><br></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>5. AV Нодална Реентри Тахикардия (AVNRT)</h2><p>AV нодалната реентри тахикардия е много честа форма на аритмия.</p><h3>Анатомичен субстрат и физиология</h3><p>В нормалното сърце AV възелът притежава предсърдни разклонения, които могат да формират два (или повече) потенциални пътя за провеждане:</p><ol><li><strong>Бърз път:</strong> Характеризира се с голяма скорост на провеждане, но има сравнително <strong>дълъг рефрактерен период</strong>.</li><li><strong>Бавен път:</strong> Демонстрира по-бавно провеждане, но обикновено има <strong>по-къс рефрактерен период</strong>.</li></ol><p><strong>Нормално провеждане:</strong> Стимулът преминава и по двата пътя, но импулсът по бързия път достига пръв до снопа на Хис. Когато импулсът от бавния път стигне дотам, той заварва рефрактерна тъкан и се гаси. Така в нормални условия само импулсът от бързия път продължава към камерите.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774522967568-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774522967568-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1352px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Механизъм на аритмията (Reentry)</h3><p>Аритмията често се отключва от <strong>предсърдна екстрасистола</strong>:</p><ul><li><strong>Еднопосочен блок:</strong> Тъй като бързият път има дълъг рефрактерен период, една ранна екстрасистола го заварва в състояние на невъзбудимост. Импулсът обаче успява да премине по <strong>бавния път</strong>, който вече се е възстановил.</li><li><strong>Затваряне на веригата:</strong> Докато импулсът бавно се придвижва надолу и достигне компактната част на AV възела, дисталният край на бързия път вече е имал време да се реполяризира.</li><li><strong>Реентри:</strong> Импулсът се разпространява както напред (към камерите), така и <strong>ретроградно </strong>нагоре по бързия път към предсърдията. Достигайки предсърдията, той може да се върне обратно надолу по бавния път, затваряйки реентри веригата и поддържайки тахикардията.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774191477303-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774191477303-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774191477303-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 732px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>ЕКГ характеристики</h3><p>Диагностиката на AVNRT изисква прецизно търсене на ретроградната P-вълна, която поради високата скорост на провеждане през „бързия път“ често се застъпва с камерния комплекс. Основната находка е <strong>правилна тахикардия </strong>с тесни QRS комплекси (обикновено <strong>150–250 bpm</strong>), но специфичните детайли се крият в терминалната част на QRS:</p><ul><li><strong>Феноменът на „скритата“ P-вълна:</strong> При най-честата форма (Slow-Fast) предсърдията и камерите се деполяризират почти едновременно. P-вълната обикновено е „погребана“ в QRS комплекса и не се вижда като отделен елемент.</li><li><strong>Псевдо-r' в отвеждане V1:</strong>&nbsp;Ретроградната P-вълна се появява веднага след QRS и имитира малко второ зъбче „r“. За да се потвърди, че това е „псевдо“ вълна, тя трябва да изчезне при възстановяване на синусовия ритъм.</li><li><strong>Псевдо-s в долните отвеждания (II, III, aVF):</strong> Тъй като предсърдията се активират ретроградно, P-вълната е отрицателна. Тя се наслоява върху края на QRS комплекса и изглежда като тясно, дълбоко зъбче „s“, което липсва в нормалния запис на пациента.</li><li><strong>Анормални P-вълни при Uncommon AVNRT:</strong> При рядката форма импулсът се движи надолу по бързият, а ретроградно по „бавния път“, което отнема повече време. В този случай P-вълната не е скрита, а е ясно видима <strong>след</strong> QRS комплекса (дълъг RP интервал) и е инвертирана в долните отвеждания.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-31/text-editor-images/2026/03/1774965181552-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-31/text-editor-images/2026/03/1774965181552-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1181px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Клинична картина</h3><p>Обикновено се появява при тийнейджъри или млади хора. Понася се добре, но причинява плашещи палпитации. При много висока честота може да доведе до замаяност или задух. При възрастни или хора със сърдечни заболявания може да причини синкоп, стенокардия или белодробен оток.</p><h3>Лечение</h3><h4>Остро лечение (прекратяване на пристъпа):</h4><p>Целта е да се наруши проводимостта в AV възела:</p><ol><li><strong></strong><p><strong>Вагусови маневри (маневър на Валсалва или масаж на каротидния синус)</strong>: чрез тях се цели прекъсване на реципрочната (re-entry) верига и терминиране на аритмията или най-малкото – забавяне на камерната честота, което позволява по-лесна визуализация на P-вълните и прецизиране на диагнозата.</p></li><li><strong>Adenosine:</strong> Най-бързото и ефективно фармакологично средство (интравенозно).</li><li><strong>Други опции:</strong> Интравенозни калциеви антагонисти (верапамил, дилтиазем) или бета-блокери, електрическо кардиоверзио (ако пациентът е в шок или колапс)</li></ol><h4>Дългосрочно лечение (превенция):</h4><ul><li><strong>Медикаменти:</strong> Орални бета-блокери, калциеви блокери или дигоксин при чести епизоди.</li><li><strong>Катетърна аблация:</strong> Обгаряне на бавния път. Високоефективна, но носи малък риск (под 2%) от пълен AV блок (поради засягане на бързия път), което би наложило постоянен пейсмейкър.</li><li><strong>Клас IA или IC антиаритмици:</strong> Ефективни, но по-малко желани от аблацията поради потенциална токсичност.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>6. Синдром на камерно превъзбуждане (WPW синдром)</h2><p>При пациенти с камерно превъзбуждане (известно още като синдром на <strong>Wolff–Parkinson–White [WPW]</strong>), предсърдните импулси могат да преминават антеградно към камерите както през AV възела, така и през <strong>допълнителна проводна връзка</strong> (accessory pathway). <img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774191009209-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774191009209-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 844px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>ЕКГ характеристики по време на синусов ритъм</h3><p>Тъй като провеждането през допълнителната връзка обикновено е по-бързо от това през AV възела, камерите се стимулират по-рано от нормалното. Това създава характерен ЕКГ образ.</p><ol><li><strong>Къс PR-интервал (&lt; 0.12 sec):</strong> Камерната стимулация започва по-рано поради бързото преминаване през допълнителната връзка.</li><li><strong>Делта вълна:</strong> Първоначалната част на QRS комплекса е полегата, а не остра. Това се дължи на факта, че началната камерна активация през допълнителната връзка е по-бавна от тази през специализираната система на Пуркиние.</li><li><strong>Разширен QRS комплекс:</strong> Представлява „фузия“ на два фронта на възбуждане — един от допълнителната връзка и един от нормалната система на Хис-Пуркиние.</li></ol><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-22/text-editor-images/2026/03/1774191142983-image.png &quot;width=100%&quot;)\" id=\"note-1775459217906-0\">Видове аритмии при WPW синдром</span></h3><p>Пациентите с WPW са предразположени към пароксизмални суправентрикуларни тахикардии, тъй като допълнителната връзка служи като рамо на <strong>reentry верига</strong>.</p><h4>А. Ортодромна AVRT (Orthodromic AVRT)</h4><p>Най-честата тахикардия при тези пациенти.</p><ul><li><strong>Механизъм:</strong> Импулсът се движи антеградно надолу през <strong>AV възела</strong> към камерите и след това ретроградно нагоре през <strong>допълнителната връзка</strong> към предсърдията.</li><li><strong>ЕКГ:</strong> Тъй като камерите се деполяризират изключително през нормалната проводна система, <strong>няма делта вълна</strong> и QRS е с нормална ширина. Ретроградни P-вълни често се виждат веднага след всеки QRS.</li></ul><h4>Б. Антидромна AVRT (Antidromic AVRT)</h4><p>Среща се при по-малко от 10% от пациентите.</p><ul><li><strong>Механизъм:</strong> Импулсът се движи антеградно надолу през <strong>допълнителната връзка</strong> и ретроградно нагоре през <strong>AV възела</strong>.</li><li><strong>ЕКГ:</strong> Характеризира се с <strong>широк QRS комплекс</strong>, тъй като камерите се активират изцяло през допълнителната връзка. Трудно се различава от камерна тахикардия само по ЕКГ.</li></ul><h4>В. Предсърдно мъждене (AF) или трептене при WPW</h4><p>Това е третият и най-опасен тип аритмия. Някои допълнителни връзки имат много къси рефрактерни периоди, което позволява камерна честота до <strong>300 bpm</strong>. Такива честоти могат да доведат до камерно мъждене и сърдечен арест, дори при млади и здрави пациенти.</p><h3>Фармакологично управление и предпазни мерки</h3><p>Лечението при WPW изисква голямо внимание.</p><ul><li><strong>Опасни лекарства:</strong> Дигиталис, бета-блокери и някои калциеви антагонисти блокират AV възела, но не и допълнителната връзка. Те могат парадоксално да скъсят нейния рефрактерен период и да ускорят камерната честота при AF или трептене, водещо до хемодинамичен колапс.</li><li><strong>Предпочитани лекарства:</strong> Блокери на натриевите канали (клас IA и IC) и някои лекарства от клас III. Те забавят провеждането и удължават рефрактерността както на допълнителната връзка, така и на AV възела.</li></ul><h3>Остро и дефинитивно лечение</h3><ol><li><strong>При хемодинамичен колапс:</strong> Незабавно електрическо кардиоверзио.</li><li><strong>При стабилни пациенти:</strong> Интравенозен <strong>procainamide</strong> (клас IA) или <strong>ibutilide</strong> (клас III) за прекъсване на аритмията.</li><li><strong>Дефинитивно лечение:</strong> Радиочестотна <strong>катетърна аблация</strong> на допълнителната връзка. Тя прекъсва провеждането през нея и напълно излекува състоянието. Ако аблацията не е възможна, се провежда хронична перорална терапия с антиаритмици от клас IA, IC или III.</li></ol><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">КАМЕРНИ АРИТМИИ</h1><p>Основните камерни аритмии са: <strong>камерни екстрасистоли</strong>, <strong>камерна тахикардия </strong>и <strong>камерно мъждене</strong>. Камерните аритмии обикновено са по-опасни от суправентрикуларните и са отговорни за голяма част от случаите на внезапна сърдечна смърт.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>1. Камерни Екстрасистоли (Ventricular Premature Beats - VPBs)</h2><p><em>Най-честата камерна аритмия</em><em><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774524475992-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774524475992-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774524475992-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1014px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></em></p><h3>Патофизиология и ЕКГ характеристики</h3><p>Камерната екстрасистола (PVC) възниква, когато ектопично огнище в камерите генерира импулс преди следващия нормален синусов удар.</p><ul><li><strong>QRS морфология:</strong> Комплексът е <strong>разширен (≥ 0.12 сек)</strong> и деформиран (\"бизарен\"). Причината е бавното разпространение на импулса от клетка на клетка, заобикаляйки бързата система на Хис-Пуркиние.</li><li><strong>P-вълна:</strong> Обикновено липсва предхождаща P-вълна. Понякога може да се види ретроградна P-вълна след QRS.</li><li><strong>Компенсаторна пауза:</strong> PVC обикновено е последвана от пълна компенсаторна пауза преди следващия синусов удар.</li><li><strong>Интерполирани PVC:</strong> Рядка форма, при която екстрасистолата се \"вклинява\" между два нормални удара без последваща пауза.</li></ul><h3>Ритмични модели</h3><p>Екстрасистолите могат да се появяват в специфични повтарящи се конфигурации:</p><ul><li><strong>Бигеминия:</strong> Всеки втори удар е камерна екстрасистола (редуване 1:1 с нормален удар).</li><li><strong>Тригеминия:</strong> На всеки два нормални удара следва една камерна екстрасистола.</li><li><strong>Куплети:</strong> Две последователни камерни екстрасистоли.</li><li><strong>Триплети:</strong> Три последователни камерни екстрасистоли.</li></ul><h3>Кога PVC са опасни? (Правила за \"Злокачественост\")</h3><p>В здраво сърце PVC са доброкачествени. Трябва да се внимава в следните случаи:</p><ol><li><strong>Чести PVC:</strong> Когато съставляват над 10% от всички удари (може да доведат до дилатативна кардиомиопатия).</li><li><strong>Consecutive PVC:</strong> Поредици от три или повече последователни PVC (това вече се дефинира като камерна тахикардия).</li><li><strong>Мултиформени PVC:</strong> Екстрасистоли с различна морфология, което показва произход от множество ектопични огнища.</li><li><strong>Феномен \"R-върху-T\" (R-on-T):</strong> Когато PVC попада върху T-вълната на предходния удар. Това е уязвим период, който може да провокира камерно мъждене.</li><li><strong>Остър миокарден инфаркт:</strong> Всяка PVC в контекста на остър инфаркт е опасна, защото може да отключи фатална аритмия.</li></ol><h3>Клинично поведение и Лечение</h3><ul><li><strong>Здрави хора:</strong> Обикновено не изискват лечение. При симптоми се използват <strong>бета-блокери</strong> и успокояване на пациента.</li><li><strong>Структурни увреждания:</strong> При пациенти със сърдечна недостатъчност или стар инфаркт, PVC са маркер за повишен риск от внезапна смърт.</li><li><strong>Терапия:</strong></li><ul><li><strong>Медикаменти:</strong> Бета-блокери. Подтискането на PVC с антиаритмици не винаги намалява смъртността.</li><li><strong>Аблация:</strong> При много чести екстрасистоли (над 10–20%), причиняващи дисфункция на камерата.</li><li><strong>ICD:</strong> При висок риск от камерно мъждене се имплантира кардиовертер-дефибрилатор.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>2. Камерна Тахикардия (Ventricular Tachycardia - VT)</h2><p><em>Дефиниция: Поредица от три или повече последователни камерни екстрасистоли (PVCs).</em></p><h3>Класификация според продължителността</h3><ul><li><strong>Устойчива (Sustained VT):</strong> Продължава<strong> над 30 секунди</strong> или предизвиква хемодинамичен колапс (хипотония, синкоп). Изисква спешна интервенция.</li><li><strong>Неустойчива (Nonsustained VT):</strong> Епизоди, които се прекратяват спонтанно за по-малко от 30 секунди.</li></ul><h3>Етиология и Патофизиология</h3><p>Най-често се среща при пациенти със <strong>структурни сърдечни заболявания</strong>:</p><ul><li><strong>Исхемия и инфаркт:</strong> Острият инфаркт (особено в първите 48 часа) е висок рисков фактор. Старите цикатрикси от инфаркт са най-честият субстрат за re-entry.</li><li><strong>Сърдечна недостатъчност:</strong> Камерната дилатация и фиброза предразполагат към аритмия.</li><li><strong></strong><p><strong>Първични електрически заболявания</strong> (напр. синдром на дългия QT интервал).</p></li><li><strong>Клапни пороци и вродени сърдечни аномалии</strong>.</li></ul><h3>ЕКГ Характеристики</h3><ul><li><strong>Честота и ритъм:</strong> Обикновено между <strong>120 и 200 bpm</strong>. Ритъмът е предимно правилен, но може да показва лека нерегулярност</li><li><strong>QRS морфология:&nbsp;</strong>Разширени комплекси (<strong>≥ 0.12 sec</strong>) с деформирана, „бизарна“ конфигурация.</li></ul><h3>Специфични диагностични белези</h3><p>При камерна тахикардия предсърдията и камерите често бият независимо едни от други (AV дисоциация). Понякога синусовият импулс успява да „пробие“ към камерите, което създава два феномена:</p><ul><li><p><strong>AV дисоциация:</strong> Предсърдията и камерите функционират независимо. Присъствието на P-вълни, които нямат постоянна връзка с QRS комплексите, е сигурен белег за VT.</p></li><li><p><strong>Capture beats:</strong> </p><p>Епизодичен нормален (тесен) QRS комплекс, възникващ, когато синусов импулс успее да деполяризира камерите в техния извънрефрактерен период.</p></li><li><p><strong>Fusion beats:</strong> </p><p>Хибриден QRS комплекс (по-тесен от тези на тахикардията, но по-широк от нормалния), получен при едновременна активация на камерите от синусов и камерен импулс.</p></li><li><p><strong>Прекордиална конкордантност:</strong> Състояние, при което всички QRS комплекси в отвесите от V1 до V6 имат еднаква посока (поляритет):</p><br></li><ul><li><p><strong>Положителна:</strong> Всички QRS сочат нагоре (задна стена на ЛК).</p><br></li><li><p><strong>Отрицателна:</strong> Всички QRS сочат надолу (връх на ЛК). Отрицателната конкордантност е практически 100% специфична за VT.</p><br></li></ul></ul><p><img src=\"https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fmedschool.co%2Fimages%2Fdetail%2Fecg%2Ffusioncapture.gif&amp;f=1&amp;nofb=1&amp;ipt=e06a3d5b32f3a8e2b02a4d17f60804ba2bbbaf0cee79601d3ec664cb554dfd2e\" alt=\"https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fmedschool.co%2Fimages%2Fdetail%2Fecg%2Ffusioncapture.gif&amp;f=1&amp;nofb=1&amp;ipt=e06a3d5b32f3a8e2b02a4d17f60804ba2bbbaf0cee79601d3ec664cb554dfd2e\" data-original-src=\"https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fmedschool.co%2Fimages%2Fdetail%2Fecg%2Ffusioncapture.gif&amp;f=1&amp;nofb=1&amp;ipt=e06a3d5b32f3a8e2b02a4d17f60804ba2bbbaf0cee79601d3ec664cb554dfd2e\" data-width=\"50\" data-align=\"center\" style=\"width: 600px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Класификация според морфологията:</h3><ol><li><strong>Мономорфна VT:</strong></li><ul><li><strong>Вид:</strong> Всеки QRS комплекс изглежда идентичен с предходния.</li><li><strong>Субстрат:</strong> Обикновено се дължи на фиксирана re-entry верига около зона на миокарден цикатрикс.</li><li><strong>Идиопатична VT:</strong> Среща се при здрави хора и е с по-добра прогноза.</li></ul><li><strong>Полиморфна VT:</strong></li><ul><li><strong>Вид:</strong> QRS комплексите постоянно променят формата и оста си от удар до удар.</li><li><p><strong>Механизъм:</strong> Дължи се на множество ектопични огнища или постоянно променяща се reentry верига.</p><br></li><li><strong>Причини:</strong> Остра исхемия, тежки електролитни нарушения или удължен QT интервал.</li><li><strong>Риск:</strong> Много често дегенерира в камерно мъждене и сърдечен арест.</li><li><strong>Примери: </strong>Torsades de Pointes, <span class=\"editor-note\" data-note=\"## Двупосочна камерна тахикардия (Bidirectional VT)\nТова е особен вариант на камерна тахикардия, при който се наблюдава редуване на електрическата ос на QRS комплексите от удар до удар (обикновено между -30° и +110°).\n- **ЕКГ характеристики:** На записа изглежда така, сякаш върховете на QRS комплексите сочат алтернативно нагоре и надолу. Обикновено е съчетана с десен бедрен блок (RBBB).\n- **Етиология и механизъм:** - Дигиталисова интоксикация: Исторически това е най-честата причина. Предозирането с дигиталисови гликозиди води до калциево претоварване на клетките. - Катехоламинергична полиморфна камерна тахикардия (CPVT): Генетично заболяване, при което двупосочната VT се провокира от физическо натоварване или емоционален стрес. - Тежка сърдечна недостатъчност: Рядко се наблюдава при напреднала кардиомиопатия.\" id=\"note-1775157678315-0\">bidirectional VT</span>.</li></ul></ol><h3>Клинична класификация според перфузията</h3><p><strong>Пулсова камерна тахикардия:</strong></p><p>При нея сърцето все още успява да генерира достатъчен ударен обем, за да се палпира периферен пулс. Тя се дели на:</p><ul><li><p><strong>Стабилна: </strong>Пациентът е в съзнание, без признаци на шок, сърдечна недостатъчност или гръдна болка. </p><p><strong>Лечение</strong>: Медикаментозно (Амиодарон).</p><strong><br></strong></li><li><p><strong>Нестабилна</strong>: Пациентът има пулс, но е с хипотония, променено съзнание или белодробен едем. </p><p><strong>Лечение</strong>: Синхронизирана електрокардиоверзия.</p></li></ul><p><strong>Безпулсова камерна тахикардия:</strong></p><p>Това е състояние на сърдечен арест. Сърцето се съкращава толкова бързо и неефективно, че сърдечният дебит е нулев и не се палпира пулс.</p><ul><li><p><strong>Клинично значение: </strong>Третира се идентично с камерното мъждене (VF).</p></li><li><p style=\"font-weight: bold\">Подход: </p><p>Незабавна дефибрилация и кардиопулмонална реанимация.</p></li></ul><h3>Клинична картина</h3><h4>1. Симптоматика</h4><ul><li><strong>Леки форми:</strong> Ако тахикардията е сравнително бавна (<strong>&lt; 130 bpm</strong>) и лявата камера е със запазена функция, пациентът може да усеща единствено палпитации (сърцебиене) или лек дискомфорт.</li><li><strong>Типични симптоми:</strong> Задух, гръдна болка (ангинозна болка поради исхемия) и замайване.</li></ul><h4>2. Тежки последствия и Хемодинамика</h4><p>При устойчива VT камерното пълнене е критично скъсено, което води до рязък спад в сърдечния дебит. Това може да причини:</p><ul><li><strong>Синкоп:</strong> Поради внезапна хипоперфузия на мозъка.</li><li><strong>Белодробен оток:</strong> Остра левокамерна недостатъчност в резултат на високата честота.</li><li><strong>Сърдечен арест:</strong> Дегенерация на VT в камерно мъждене.</li></ul><h4>3. Рисков профил</h4><ul><li><strong>Висок риск:</strong> Пациенти с вече увредена камерна функция (ниска фракция на изтласкване) понасят VT изключително тежко хемодинамично.</li><li><strong>Прогностичен белег:</strong> Появата на устойчива VT в първите 6 седмици след миокарден инфаркт е маркер за <strong>висока едногодишна смъртност</strong>.</li></ul><h3>Лечение</h3><h4>1. Спешна помощ</h4><ul><li><strong>Хемодинамично нестабилни:</strong> Незабавно <strong>електрическо кардиоверзио</strong> (дефибрилация, ако няма пулс).</li><li><strong>Стабилни пациенти:</strong> Интравенозни антиаритмици (<strong>Amiodarone, Procainamide</strong> или <strong>Lidocaine</strong>).</li></ul><h4>2. Дългосрочна профилактика</h4><p>След овладяване на пристъпа е жизненоважно да се лекуват причините:</p><ul><li><strong>Корекция:</strong> Електролити (K+, Mg++), лечение на исхемията.</li><li><strong>ICD (Имплантируем дефибрилатор):</strong> Основен метод при пациенти със структурни увреждания за превенция на внезапна сърдечна смърт.</li><li><strong>Катетърна аблация:</strong> Прилага се за унищожаване на re-entry огнището, особено при идиопатични форми или чести епизоди, провокиращи шокове от ICD.</li></ul><h4>3. Идиопатична VT (при здрави сърца)</h4><p>Среща се при хора без структурни увреждания:</p><ul><li><strong>Риск:</strong> Рядко е животозастрашаваща.</li><li><strong>Лечение:</strong> Бета-блокери, калциеви антагонисти или <strong>катетърна аблация</strong> за контрол на симптомите.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>3. Torsades de pointes</h2><p><em>Буквално: „Усукване на върховете“ – специфична форма на полиморфна камерна тахикардия.</em></p><p><em><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774525325152-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774525325152-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774525325152-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 997px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></em></p><h3>Патофизиология и Механизъм</h3><p>Torsades de Pointes (TdP) е уникална аритмия, която възниква почти изключително в контекста на <strong>удължен QT-интервал</strong>.</p><ul><li><strong>Механизъм:</strong> Дължи се на <strong>ранни следдеполяризации</strong> (тригерна активност) по време на удължената реполяризация на камерите (дълга Т-вълна).</li><li><strong>Тригер:</strong> Една камерна екстрасистола (PVC), падаща върху уязвимата удължена Т-вълна, може да инициира пристъпа.</li><li><strong>Анатомичен израз:</strong> QT-интервалът нормално съставлява около 40% от сърдечния цикъл. Когато се удължи, рискът от TdP нараства значително.</li></ul><h3>ЕКГ Характеристики</h3><p>TdP изглежда като обикновена камерна тахикардия, но със специфична динамика:</p><ul><li><strong>Морфология:</strong> QRS комплексите постоянно променят своята ос и амплитуда, сякаш се <strong>„усукват“ около изоелектричната линия</strong>.</li><li><strong>Вълнообразен вид:</strong> Комплексите преминават от положителни към отрицателни дефлекции в спираловиден модел.</li></ul><h3>Причини за удължаване на QT-интервала</h3><ol><li><strong>Електролитни нарушения:</strong> Хипокалиемия, хипомагнезиемия и хипокалциемия.</li><li><strong>Медикаменти (най-честата причина):</strong></li><ul><li><strong>Антиаритмици:</strong> Клас IA (хинидин, прокаинамид) и Клас III (соталол, амиодарон).</li><li><strong>Антибиотици:</strong> Еритромицин, азитромицин, хинолони.</li><li><strong>Психотропни:</strong> Фенотиазини, трициклични антидепресанти, халоперидол.</li><li><strong>Други:</strong> Метадон, някои антимикотици и антихистамини.</li></ul><li><strong>Вродени състояния:</strong> Наследствени мутации в йонните канали (Конгенитален Long QT синдром).</li><li><strong>Остри състояния:</strong> Миокарден инфаркт или тежка брадикардия.</li></ol><h3>Клинично значение и Опасности</h3><ul><li><strong>Симптоми:</strong> Аритмията обикновено е симптомна – причинява внезапно замаяност или <strong>синкоп</strong>.</li><li><strong>Протичане:</strong> Често епизодите са кратки и самоограничаващи се (пароксизмални).</li><li><strong>Риск:</strong> Основната опасност е дегенерацията на TdP в <strong>камерно мъждене</strong>, което води до внезапна смърт.</li></ul><h3>Лечение и Превенция</h3><p>Важно е TdP да се различава от стандартната камерна тахикардия, тъй като лечението е коренно различно.</p><ol><li><strong>Магнезиев сулфат (IV):</strong> Магнезият е лекарство на първи избор, дори при нормални нива на магнезий в кръвта. Той стабилизира мембраните и потиска епизодите.</li><li><strong>Прекратяване на провокатори:</strong> Спиране на всички лекарства, които удължават QT-интервала.</li><li><strong>Корекция на електролитите:</strong> Възстановяване нивата на калий и калций.</li><li><strong>Ускоряване на сърдечната честота (Скъсяване на QT):</strong></li><ul><li><strong></strong><p>Интравенозни β-адренергични стимуланти (напр. <strong>изопротеренол</strong>).</p>.</li><li><strong>Временен пейсмейкър:</strong> Често най-ефективният начин за „превземане“ на ритъма (overdrive pacing).</li></ul></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>4. Камерно Мъждене (Ventricular Fibrillation - VF)</h2><p><em>Непосредствено животозастрашаващо състояние.</em><em><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774525550860-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774525550860-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-26/text-editor-images/2026/03/1774525550860-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 979px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></em></p><h3>Патофизиология и Механизъм</h3><p>Камерното мъждене е най-честата аритмия при възрастни, претърпели внезапна сърдечна смърт. То представлява пълен електрически и механичен хаос в камерите.<em></em></p><ul><li><strong>Механизъм:</strong> Обикновено се инициира от епизод на <strong>камерна тахикардия (VT)</strong>, която дегенерира в множество малки, странстващи re-entry вълнички.</li><li><strong>Хемодинамика:</strong> Липсват координирани съкращения, което води до <strong>нулев сърдечен дебит</strong>. Сърцето не изпомпва кръв, а само \"трепти\".</li><li><strong>Последствия:</strong> Бързо води до смърт, ако не се коригира в рамките на минути.</li></ul><h3>ЕКГ Характеристики</h3><p>При камерното мъждене липсват каквито и да е разпознаваеми QRS комплекси, P-вълни или T-вълни.</p><ul><li><strong>ЕКГ находка:</strong> Хаотична, накъсана линия без ритмичност.</li><li><strong>Видове VF:</strong></li><ul><li><strong>Грубо (Coarse) VF:</strong> Линията подскача спазматично с по-голяма амплитуда (обикновено в началото).</li><li><strong>Фино (Fine) VF:</strong> Линията едва доловимо вълнообразна (обикновено при по-продължителна аритмия и изтощен миокард).</li></ul></ul><h3>Клиничен контекст и Провокатори</h3><p>VF се среща почти изключително при подлежащи сърдечни заболявания или тежки остри състояния:</p><ul><li><strong>Миокардна исхемия/инфаркт:</strong> Основна причина за смъртност при остър инфаркт.</li><li><strong>Сърдечна недостатъчност, Хипотония и Шок.</strong></li><li><strong>Електролитен дисбаланс, Хипоксемия или Ацидоза.</strong></li><li><strong>Предозиране със стимуланти:</strong> Особено комбинации (напр. MDMA/Екстази плюс амфетамини).</li></ul><h3>Лечение и Спешни мерки</h3><p>Всяка секунда е критична за оцеляването на пациента.</p><ol><li><strong>Незабавна дефибрилация:</strong> Единствената ефективна терапия за прекратяване на VF и \"рестартиране\" на сърцето.</li><li><strong>Кардиопулмонална реанимация:</strong> Трябва да започне веднага и да продължи до пристигането на дефибрилатор.</li><li><strong>Корекция на причините:</strong> След възстановяване на ритъма се коригират хипоксемията, електролитите (K+, Mg++) и киселинно-алкалното състояние.</li><li><strong>Медикаментозна подкрепа:</strong> Интравенозни антиаритмици (напр. <strong>Amiodarone</strong>) за предотвратяване на рецидив.</li><li><strong>Дългосрочна защита:</strong> <p>Ако не се открие обратим провокиращ фактор, оцелелите от VF обикновено получават </p><strong>имплантируем кардиовертер-дефибрилатор (ICD)</strong>.</li></ol><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Рандъм неща</h1><h2>Техника на каротиден масаж (Carotid Sinus Massage)</h2><p>Каротидният масаж е мощна вагусова маневра, която трябва да се прилага с изключително внимание и при спазване на строги правила за безопасност.</p><h3>1. Предварителна аускултация</h3><p>Преди процедурата задължително <strong>аускултирайте за каротидни шумови явления (bruits)</strong>. </p><ul><li><strong>Цел:</strong> Да се избегне пълното прекъсване на кръвотока към мозъка или дислокацията на атеросклеротична плака (риск от инсулт). </li><li><strong>Противопоказание:</strong> При наличие на данни за значима каротидна стеноза или съдова болест, масажът <strong>не се извършва</strong>.</li></ul><h3>2. Позициониране на пациента</h3><p>Пациентът трябва да бъде в <strong>легнало положение</strong>. Шията се екстензира, а главата се ротира леко в обратна на оператора посока.</p><h3>3. Техника на изпълнение</h3><ul><li>Палпирайте каротидната артерия в областта на <strong>ъгъла на долната челюст</strong> (carotid sinus).</li><li>Приложете умерен натиск в продължение на <strong>10 до 15 секунди</strong>. </li><li><strong>Сила на натиска:</strong> Приложете сила, еквивалентна на тази, необходима за леко притискане на топка за тенис.</li></ul><h3>4. Златно правило за безопасност</h3><p><strong>Никога не притискайте двете каротидни артерии едновременно!</strong> Това може да предизвика тежка церебрална исхемия.</p><h3>5. Последователност</h3><ul><li>Започнете първо с <strong>дясната каротидна артерия</strong>, тъй като успеваемостта при нея е статистически по-висока.</li><li>Ако опитът отдясно е неуспешен, преминете към масаж на лявата страна.</li></ul><h3>6. Мониториране и безопасност</h3><ul><li>По време на цялата процедура трябва да се записва <strong>ЕКГ лента</strong>, за да се проследи ефектът върху ритъма в реално време.</li><li><strong>Винаги</strong> разполагайте с оборудване за реанимация в непосредствена близост. В редки случаи каротидният масаж може да индуцира <strong>синус арест</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: left\">Кръвоснабдяване</h1><h3>Анатомия на коронарните артерии</h3><p>Схематичното описание на лявата и дясната коронарни артерии демонстрира тяхното взаимно разположение и областите, които те перфузират:</p><ul><li><strong>Лява главна коронарна артерия:</strong> Тя се разклонява на два основни съда:</li><ul><li><strong>Циркумфлексна артерия:</strong> Перфузира латералните и задните региони на лявата камера.</li><li><strong>Предна десцендентна артерия:</strong> Перфузира предната стена на лявата камера, предната част на междукамерния септум, както и част от предната стена на дясната камера.</li></ul><li><strong>Дясна коронарна артерия:</strong> </li><ul><li>Основно перфузира <strong>дясната камера</strong>.</li><li>Чрез своите терминални разклонения тя захранва и вариращи части от задната стена на лявата камера.</li><li><strong>Задна десцендентна артерия:</strong> В повечето случаи тя произлиза директно от дясната коронарна артерия.</li></ul></ul><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775149504978-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-02/text-editor-images/2026/04/1775149504978-image.png\" data-width=\"100\" data-align=\"left\" style=\"width: 453px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto 8px 0px\" data-broken-cleanup-bound=\"1\"><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><br><br><br><br><p><br></p><br><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
